import{_ as o}from"./chunks/morph-animation.D7Fy88Yp.js";import{_ as r,C as a,o as i,c as n,E as l,a2 as s}from"./chunks/framework.CkaEw-3u.js";const b=JSON.parse('{"title":"モーフアニメーションを作る","description":"文字列から別の文字列へ滑らかに変形させる手順と調整のコツ","frontmatter":{"title":"モーフアニメーションを作る","description":"文字列から別の文字列へ滑らかに変形させる手順と調整のコツ","pageClass":"feature-guide","aside":false},"headers":[],"relativePath":"features/feature-morph.md","filePath":"features/feature-morph.md"}'),d={name:"features/feature-morph.md"};function c(g,e,p,h,m,u){const t=a("FeatureHero");return i(),n("div",null,[l(t,{eyebrow:"MORPH & TRANSITION",title:"言葉から言葉へ、形をつないでいく",description:"テキストAのアウトラインからテキストBへ、パーツ同士を対応づけて滑らかに変形。Progressへ2つのキーフレームを置くだけで、文字が溶け合うトランジションを作れます。",image:"/image/morph.webp","image-alt":"文字列が別の文字列へ変形するモーフアニメーション","detail-link":"/reference/reference-global-settings#-モーフアニメーション-morph-animation","point-one":"2キーでアニメーション","point-two":"自動パーツ対応","point-three":"同一文字を優先"}),e[0]||(e[0]=s('<h2 id="使い方" tabindex="-1">使い方 <a class="header-anchor" href="#使い方" aria-label="Permalink to &quot;使い方&quot;">​</a></h2><ol><li><strong>Page</strong> を <code>Global Settings</code> にします。</li><li><strong>Text</strong> に変形元の文字列を入力します。</li><li><strong>Morph Animation</strong> を開き、<strong>Enable Morph</strong> をオンにします。</li><li><strong>To Text</strong> に変形先の文字列を入力します。</li><li>開始フレームで <strong>Progress</strong> を <code>0</code> にしてキーフレームを設定します。</li><li>終了フレームで Progress を <code>1</code> にします。</li></ol><p><img src="'+o+'" alt="モーフ設定の変化"></p><p><code>0</code> は Text、<code>1</code> は To Text の形です。中間の値では両者のパーツを補間します。キーフレームの間隔とカーブで速度感を調整してください。</p><h2 id="対応づけを調整する" tabindex="-1">対応づけを調整する <a class="header-anchor" href="#対応づけを調整する" aria-label="Permalink to &quot;対応づけを調整する&quot;">​</a></h2><p>文字数や形が大きく異なるときは、内部で「どのパーツからどのパーツへ変形するか」を推定します。</p><table tabindex="0"><thead><tr><th>パラメーター</th><th>調整する場面</th></tr></thead><tbody><tr><td><strong>Matching Strength</strong></td><td>面積や形の近さを重視して対応づけたいとき。<code>0</code> では位置の近さを優先します。</td></tr><tr><td><strong>Same Glyph Priority</strong></td><td>両方に同じ文字があるとき、その文字同士を優先して結びたいとき。</td></tr></tbody></table><p>まずデフォルト値で動きを確認し、パーツが不自然に交差するときだけ少しずつ変更するのがおすすめです。</p><h2 id="きれいに見せるコツ" tabindex="-1">きれいに見せるコツ <a class="header-anchor" href="#きれいに見せるコツ" aria-label="Permalink to &quot;きれいに見せるコツ&quot;">​</a></h2><ul><li>元と先で <strong>Horizontal Alignment</strong> と <strong>Vertical Alignment</strong> の基準を揃えます。</li><li>同じ文字を同じ位置に残したい場合は Same Glyph Priority を上げます。</li><li>形が大きく異なる文字列では、Progress の中間を短くすると変形の複雑さが目立ちにくくなります。</li><li>縦方向の位置が揺れる場合は Vertical Alignment の <code>Baseline</code> を試します。</li><li>対応づけが思い通りにならないときは、<strong>Horizontal Alignment</strong> を <code>Center</code> から <code>Left</code> や <code>Right</code> に変更してみます。文字の位置関係が変わるため、対応づけの結果も変化します。</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>パーツの分かれ方はフォントのアウトライン構造に依存します。同じ文字列でも、フォントを変えるとモーフの対応や動きが変わることがあります。</p></div>',11))])}const P=r(d,[["render",c]]);export{b as __pageData,P as default};
